VALUES
  ('disabled-6e2f88c7-moex-00037', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '下列何項行為，得以代理方式為之？', '["侵權行為", "發現埋藏物", "無因管理", "設定普通抵押權 30840"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00038', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '甲與乙訂立消費借貸契約，向乙借貸新臺幣100萬元，雙方約定借貸期間 2年，年利率百分之二十五，甲均依約定清償本金與利息。下列何者正確？', '["甲與乙關於本金與利息之約定均有效", "年利率超過百分之二十者，超過部分之約定有效，但乙無請求權", "約定利率超過週年百分之十六者，超過部分之約定，無效", "甲對乙給付利息後，不得主張不當得利返還請求權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00039', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '乙未受甲之委任，卻為甲墊款繳納稅捐。下列何者正確？', '["乙之行為無論是否違反甲之意思，均得依無因管理請求甲償還墊款並加 給利息", "乙之行為無論是否違反甲之意思，均得依無因管理請求甲償還墊款，但 不得加給利息", "乙之行為須不違反甲之意思，始得依無因管理請求甲償還墊款並加給利息", "乙之行為須不違反甲之意思，始得依無因管理請求甲償還墊款，但不得 加給利息"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00040', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '依民法給付遲延之催告相關規定，下列何者錯誤？', '["於債務人陷於給付遲延後，債權人得依第254條定相當期限催告債務人給 付，債權人於催告所定之相當期限屆滿時起，始取得契約之解除權", "倘若給付有確定期限者，依第229條第1項，無待債權人催告，債務人於 期限屆滿時起，陷於給付遲延。然債權人須依第254條定相當期限催告債 務人給付，債權人於催告所定之相當期限屆滿時起，始取得契約之解除權", "絕對定期行為之債務，非於一定時期給付不能達契約之目的，依第229條 第1項，債務人於期限屆滿時起，陷於給付遲延，且依第255條，債權人 無須催告，即取得契約之解除權", "債權人依第229條第2項所為之催告，倘若未定期限或所定期限不相當， 不生催告之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00041', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '乙與甲訂立 A 屋租賃契約，承租甲之 A 屋供丙使用。因甲對 A 屋保管有 欠缺，壁磚剝落致行人丁受傷。有關丁應向何者請求損害賠償，下列何者 正確？', '["丁應向甲請求損害賠償", "丁應向乙請求損害賠償", "丙應單獨對丁負賠償責任", "甲乙丙對丁應連帶負責任 30840"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00042', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '依民法第750條，保證人受主債務人之委任而為保證者，有下列何種情形 時，不得向主債務人請求除去其保證責任？', '["主債務人履行債務遲延者", "主債務人之財產顯形減少者", "主債務人另委任他人為第二保證人者", "保證契約成立後，主債務人之住所、營業所或居所有變更，致向其請求 清償發生困難者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00043', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '依民法規定，下列何者並非要式契約？', '["人事保證契約", "合會契約", "保證契約", "二年期間之房屋租賃契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00044', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '甲欲購買乙之 A 地，不欲讓乙知悉此事，即委任丙處理之。下列何者 錯誤？', '["乙與丙訂立買賣契約，並將 A 地所有權移轉登記於丙，丙取得 A 地之 所有權", "丙取得 A 地之所有權後，以 A 地為標的，再讓與丁，丙之行為構成無 權處分", "丙取得A地之所有權後，應將A地所有權移轉於甲", "委任終止後，丙應將事務處理之始末，對甲為詳細明確之報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00045', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '依民法第759條規定，非因法律行為所生之不動產物權變動之情形中，下 列何者非屬該條所稱「法院之判決」？', '["依暴利行為所為撤銷不動產物權行為之判決", "依詐害債權行為所為撤銷不動產物權行為之判決", "分割共有不動產所有權之判決", "法院命被告履行不動產物權移轉登記之判決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00046', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '直接對物有事實上之管領力，而對物加以管領支配之人，為直接占有人。 下列何者非屬之？', '["普通地上權人", "動產質權人", "普通抵押權人", "房屋承租人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL)
